/-- The balanced deterministic half-sample split. -/
def splitIndices (n : ℕ) (j : Fin 2) : Finset (Fin n) :=
  if j = 0 then Finset.univ.filter (fun i => i.1 < n / 2)
  else Finset.univ.filter (fun i => n / 2 ≤ i.1)

